static inline float traverse_tree(int tree_id, const float* x) {
    const OptTree* tree = &TREES[tree_id];
    uint32_t idx = tree->start_idx;
    while (idx < tree->start_idx + tree->node_count) {
        const OptNode* node = &NODES[idx];
        if (node->is_leaf) return SHARED_LEAVES[node->u.leaf_idx];
        float t = decode_threshold(node->u.internal.threshold_q);
        idx = tree->start_idx + (x[node->u.internal.feature] < t
              ? node->u.internal.left : node->u.internal.right);
    }
    return 0.0f;
}
void predict(const float* x, float* out) {
    for (int c = 0; c < N_CLASSES; c++) out[c] = 0.000000f;
    for (int i = 0; i < N_TREES; i++) out[i % N_CLASSES] += traverse_tree(i, x);
    float mx = out[0], s = 0.0f;
    for (int c = 1; c < N_CLASSES; c++) if (out[c] > mx) mx = out[c];
    for (int c = 0; c < N_CLASSES; c++) { out[c] = expf(out[c]-mx); s += out[c]; }
    for (int c = 0; c < N_CLASSES; c++) out[c] /= s;
}
static inline int predict_class(const float* x) {
    float p[N_CLASSES]; predict(x, p);
    int b = 0; for (int c = 1; c < N_CLASSES; c++) if (p[c]>p[b]) b=c;
    return b;
}

